&lt;p&gt;दिए गए विकल्पों में से सही उत्तर&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;विकल्प 3 &amp;#39;पानिप&amp;#39;&lt;/span&gt;&amp;nbsp;है। अन्य विकल्प इसके अनुचित उत्तर हैं।&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए शब्दों में से &amp;#39;पानिप&amp;#39; शब्द तत्सम नहीं है।&lt;/li&gt;
	&lt;li&gt;पानिप का अर्थ पानी&amp;nbsp;होता है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;अन्य सभी विकल्प तत्सम शब्द हैं।&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अन्य विकल्प:&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;तत्सम - तद्भव&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;धृष्ट - ढीठ&amp;nbsp;&lt;/p&gt;

&lt;p&gt;पृष्ठ - पीठ&amp;nbsp;&lt;/p&gt;

&lt;p&gt;पंक - कीचड़&amp;nbsp;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;background-color: rgb(255, 255, 255);&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 64px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;शब्द&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 189px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;परिभाषा&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 104px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 64px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;तत्सम&lt;/span&gt;&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;शब्द&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 189px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;ऐसे शब्द जो संस्कृत से ज्यों के त्यों लिए गए, तत्सम होते हैं।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 104px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;कूप, उष्ट्र, पंचम आदि&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 64px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;तद्भव शब्द&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 189px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;संस्कृत से हिंदी में आने पर जिन शब्दों का रूप बदल&amp;nbsp;गया हो, तद्भव कहलाते हैं।&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 104px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;आग, काम, पाँच आदि।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;मैं अंधा भी देख रहा हूँ, रोती हो तुम रोती हो। इस पंक्ति में अलंकार है-&amp;nbsp;&lt;strong&gt;&lt;u&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;विरोधाभास&lt;/span&gt;&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;(यहाँ&lt;strong&gt; &amp;quot;मैं अंधा भी देख रहा हूँ&amp;quot;&lt;/strong&gt; में&lt;strong&gt; &amp;quot;अंधा&amp;quot; &lt;/strong&gt;और&lt;strong&gt; &amp;quot;देख रहा हूँ&amp;quot; &lt;/strong&gt;ये दोनों&lt;strong&gt; विरोधी भाव&lt;/strong&gt; हैं, क्योंकि &lt;strong&gt;अंधा व्यक्ति देख नहीं सकता&lt;/strong&gt;।)&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;जब किसी&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;वस्तु का वर्णन&lt;/span&gt;&amp;nbsp;करने पर&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;विरोध नहीं&lt;/span&gt;&amp;nbsp;होने पर भी&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;विरोध का आभास&amp;nbsp;&lt;/span&gt;होता है उसे ही&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;विरोधाभास अलंकार&amp;nbsp;&lt;/span&gt;कहते है&lt;span style=&quot;text-align: center;&quot;&gt;।&lt;/span&gt;&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;​&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण-&amp;nbsp;&lt;/span&gt;सुलगी अनुराग की आग वहाँ,
	&lt;ul&gt;
		&lt;li&gt;&amp;nbsp;जल से भरपूर तड़ाग जहाँ ।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;(यहाँ &lt;strong&gt;जल&lt;/strong&gt; और &lt;strong&gt;आग &lt;/strong&gt;दो विरोधी पदार्थों का संयोग&lt;strong&gt; एक साथ दिखाया&lt;/strong&gt; गया है।)&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;2&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;span style=&quot;font-weight: 700; font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); text-align: var(--bs-body-text-align);&quot;&gt;यमक-&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;जब&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;एक ही शब्द ज्यादा बार&amp;nbsp;&lt;/span&gt;प्रयोग हो, पर हर बार&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;अर्थ अलग-अलग&amp;nbsp;&lt;/span&gt;आये वहाँ पर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;यमक अलंकार&lt;/span&gt;&amp;nbsp;होता है।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण -&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;काली घटा घनघोर, घन घन बरसे पानी।&lt;/li&gt;
				&lt;li style=&quot;margin: 0px; padding: 0px; position: relative;  line-height: 1.3;&quot;&gt;(यहाँ&lt;strong&gt; &amp;quot;घन&amp;quot; &lt;/strong&gt;शब्द &lt;strong&gt;दो&lt;/strong&gt; बार आया है। &lt;strong&gt;पहली&lt;/strong&gt; बार &lt;strong&gt;&amp;quot;घन&amp;quot; &lt;/strong&gt;का अर्थ है&lt;strong&gt; &amp;#39;बादल&amp;#39;&lt;/strong&gt; और&lt;strong&gt; दूसरी&lt;/strong&gt; बार &lt;strong&gt;&amp;quot;घन&amp;quot;&lt;/strong&gt; का अर्थ है - &amp;#39;&lt;strong&gt;घना&amp;#39;&lt;/strong&gt;।)&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;रूपक:-&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
				&lt;li&gt;जब&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;एक वस्तु&amp;nbsp;&lt;/span&gt;पर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;दूसरी वस्तु का आरोप&lt;/span&gt;&amp;nbsp;किया जाये अर्थात् जब&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;एक वस्तु&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;दूसरी वस्तु&amp;nbsp;&lt;/span&gt;का&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;रूप&amp;nbsp;&lt;/span&gt;दिया जाये तो&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;रूपक अलंकार&amp;nbsp;&lt;/span&gt;कहलाता है।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण-&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
				&lt;li&gt;सिंधु-बिहंग तरंग-पंख को फड़काकर प्रतिक्षण में।(&lt;span style=&quot;font-weight: bolder;&quot;&gt;सिंधु&lt;/span&gt;&amp;nbsp;(उपमेय) पर&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;विहंग&lt;/span&gt;&amp;nbsp;(उपमान) का तथा तरंग (उपमेय) पर पंख (उपमान) का आरोप।)&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;विभावना:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;जहाँ &lt;strong&gt;कारण &lt;/strong&gt;के न होते हुए भी&lt;strong&gt; कार्य का होना&lt;/strong&gt; पाया जाय, वहां &lt;strong&gt;विभावना अलंकार &lt;/strong&gt;होता है।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41); font-weight: 700;&quot;&gt;उदाहरण-&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;पर्वत ने जलती धूप को अपने ठंढ़े आंचल में छिपा लिया।&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(यहाँ&amp;nbsp;&lt;/span&gt;&lt;strong&gt;पर्वत का धूप को अपने आंचल &lt;/strong&gt;में छिपाना वास्तविक रूप में संभव नहीं है, लेकिन यह &lt;strong&gt;विभावना अलंकार&lt;/strong&gt; का सुंदर उदाहरण है।)&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;lsquo;सूर्य जिस पर्वत के पीछे निकलता है&amp;rsquo; &lt;/strong&gt;वाक्यांश के लिए एक शब्द होगा-&lt;strong&gt; &amp;#39;उदयाचल&amp;#39;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/mistake-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Mistake Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पश्चिम सूर्यास्त का स्थान है&lt;strong&gt; -&amp;nbsp;&lt;span style=&quot;&quot;&gt;अस्ताचल&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अनेक शब्दों&lt;/span&gt;&amp;nbsp;के लिए&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;एक शब्द&lt;/span&gt;&amp;nbsp;को प्रयुक्त करना ही&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;वाक्यांश के लिए एक शब्द&lt;/span&gt;&amp;nbsp;कहलाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कुछ महत्वपूर्ण&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;वाक्यांश के लिए एक शब्द:-&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;जिस पर मुकदमा चल रहा हो&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;- अभियुक्त&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;किसी एक में ही आस्था रखने वाला&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;-&amp;nbsp;अनन्य&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;वह चीज जिसकी चाहत हो&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;-&amp;nbsp;इच्छित&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;जिसके ऊपर किसी का उपकार हो&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;-&amp;nbsp;उपकृत&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;जो इन्द्रियों से संबंधित हो&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;-&amp;nbsp;ऐन्द्रिय&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;जिसकी बुद्धि बहुत तेज हो&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;-&amp;nbsp;कुशाग्र&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;जिसका कुछ ही समय में नाश हो जाए&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;- क्षणभंगुर&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;जो दूसरों में केवल दोषों को ही खोजता हो&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;-&amp;nbsp;छिद्रान्वेषी&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;सही उत्तर है - सुमित्रानंदन पंत।&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;लोकायतन:-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;रचयिता:-&lt;/strong&gt; सुमित्रानंदन पंत।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विधा:- &lt;/strong&gt;महाकाव्य।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;प्रकाशन वर्ष:- &lt;/strong&gt;1964&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विषय:-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;भारतीय जीवन की स्वतंत्रता के पहले और बाद की कथा।&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;यह काव्य महात्मा गाँधी के जीवन पर आधारित है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सुमित्रानंदन पंत-&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;जन्म-&lt;/span&gt;1900-1977 ई.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;मुख्य रचनाएँ-&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;छायावादी-&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;ग्रंथि(1920 ई.)&lt;/li&gt;
		&lt;li&gt;पल्लव(1926 ई.)&lt;/li&gt;
		&lt;li&gt;वीणा(1929 ई.)&lt;/li&gt;
		&lt;li&gt;गुंजन(1932ई.)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;प्रगतिवादी-&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;युगांत(1937ई.)&lt;/li&gt;
		&lt;li&gt;युगवाणी(1938ई.) आदि।&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;अरविन्द दर्शन से प्रभावित-&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;स्वर्णकिरण(1947ई.)&lt;/li&gt;
		&lt;li&gt;स्वर्ण धूलि(1947 ई.)&lt;/li&gt;
		&lt;li&gt;युगांतर(1948 ई.) आदि।&lt;/li&gt;
